{
  "summary": "This paper proposes a method to create noisy parallel code translation datasets by mining document similarity between code samples in different programming languages. Using Word Mover's Distance for similarity, the approach enables supervised training of code translation models across multiple languages despite scarce parallel corpora. The method is empirically validated on CodeNet and other datasets, showing robustness to noise and improved performance over random pairing baselines.",
  "strengths": [
    {
      "point": "Novel approach to generate noisy parallel code datasets using document similarity metrics, especially Word Mover's Distance.",
      "evidence": "The paper demonstrates that WMD outperforms other similarity methods like TF-IDF, BM25, LDA, and LSI in mining parallel code pairs."
    },
    {
      "point": "Empirical validation that code translation models trained on noisy data remain robust and achieve strong performance.",
      "evidence": "Models trained on WMD-mined noisy datasets show only moderate degradation compared to ground-truth data and outperform models trained on random pairs."
    },
    {
      "point": "Extension of code translation to 10 programming language pairs beyond commonly studied ones.",
      "evidence": "The paper creates and releases noisy parallel datasets for 10 languages from CodeNet and fine-tunes PLBART models, demonstrating practical utility."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of empirical comparison to recent unsupervised or semi-supervised code translation baselines.",
      "evidence": "No experiments or discussion include state-of-the-art unsupervised methods like back-translation or unsupervised NMT variants for code."
    },
    {
      "point": "Insufficient methodological analysis on key design choices such as similarity threshold selection and one-to-one pairing restriction.",
      "evidence": "No ablation or sensitivity studies on threshold tuning or alternative pairing strategies are provided."
    },
    {
      "point": "Evaluation relies heavily on computational accuracy @5 metric without complementary metrics or human evaluation.",
      "evidence": "No BLEU, CodeBLEU, or qualitative error analyses are reported, limiting understanding of translation quality nuances."
    },
    {
      "point": "Reproducibility is limited by partial dataset and code release and missing details on preprocessing and similarity computation.",
      "evidence": "The paper lacks detailed pipeline descriptions and clarity on which dataset portions are released."
    },
    {
      "point": "Limited discussion on dataset noise characterization, domain/style differences, and scalability of WMD for large corpora.",
      "evidence": "No quantitative noise analysis, no handling of code formatting or API differences, and no computational cost discussion."
    },
    {
      "point": "Generalisability to real-world, large-scale software projects and low-resource or domain-shifted languages remains untested.",
      "evidence": "Experiments focus on algorithmic problems from CodeNet and relatively popular languages only."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed method compare quantitatively to recent unsupervised or semi-supervised code translation approaches?",
      "motivation": "Understanding relative gains over strong baselines is critical to assess novelty and practical impact."
    },
    {
      "question": "What is the impact of varying the similarity threshold and allowing multiple pairings per target document on dataset quality and model performance?",
      "motivation": "These design choices affect dataset size, noise, and translation accuracy, influencing method robustness."
    },
    {
      "question": "Can the method scale computationally to very large codebases given the high cost of Word Mover's Distance?",
      "motivation": "Scalability is essential for real-world deployment on large software repositories."
    },
    {
      "question": "How well do models trained on noisy parallel data generalize to out-of-domain or real-world software beyond algorithmic problems?",
      "motivation": "Generalization determines practical utility beyond benchmark datasets."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
